import React from 'react';
import s from './Navbar.module.css'

const Navbar = () => {
    return (
      <div className={s.nav}>
      <div>
        <a className={s.item}>content</a>
      </div>
      <div>
        <a className={s.item}>massages</a>
      </div>
      <div>
        <a className={s.item}>card</a>
      </div>
      <div className={s.item}>media</div>
    </div>
    )

}
export default Navbar ;
